HYPOTHESIS_000003_AUTOGLUON_002_PY_1DE6FF1BE7_SOURCE = 'import numpy as np\nimport pandas as pd\n\ndef add_galactic_sightline_context(raw, deps, aux):\n    alpha_rad = np.deg2rad((pd.to_numeric(raw["alpha"], errors="coerce") % 360.0).to_numpy(dtype=float))\n    delta_rad = np.deg2rad(pd.to_numeric(raw["delta"], errors="coerce").to_numpy(dtype=float))\n\n    # Equatorial unit-sphere coordinates (wrap-safe via alpha modulo 360)\n    cos_delta = np.cos(delta_rad)\n    x_eq = cos_delta * np.cos(alpha_rad)\n    y_eq = cos_delta * np.sin(alpha_rad)\n    z_eq = np.sin(delta_rad)\n\n    # J2000 equatorial -> Galactic rotation matrix\n    x_gal = (\n        -0.0548755604 * x_eq\n        + -0.8734370902 * y_eq\n        + -0.4838350155 * z_eq\n    )\n    y_gal = (\n        0.4941094279 * x_eq\n        + -0.4448296300 * y_eq\n        + 0.7469822445 * z_eq\n    )\n    z_gal = (\n        -0.8676661490 * x_eq\n        + -0.1980763734 * y_eq\n        + 0.4559837762 * z_eq\n    )\n\n    z_clip = np.clip(z_gal, -1.0, 1.0)\n    b_rad = np.arcsin(z_clip)\n    b_deg = np.degrees(b_rad)\n    abs_b_deg = np.abs(b_deg)\n\n    l_rad = np.arctan2(y_gal, x_gal)\n    l_deg = np.degrees(l_rad) % 360.0\n    l_rad = np.deg2rad(l_deg)\n\n    sin_l = np.sin(l_rad)\n    cos_l = np.cos(l_rad)\n    sin_b = np.sin(b_rad)\n    cos_b = np.cos(b_rad)\n\n    dist_to_galactic_center = np.degrees(np.arccos(np.clip(x_gal, -1.0, 1.0)))\n    dist_to_galactic_anticenter = np.degrees(np.arccos(np.clip(-x_gal, -1.0, 1.0)))\n    dist_to_north_galactic_pole = np.degrees(np.arccos(np.clip(z_gal, -1.0, 1.0)))\n    dist_to_south_galactic_pole = np.degrees(np.arccos(np.clip(-z_gal, -1.0, 1.0)))\n\n    b_band_edges = (0.0, 10.0, 20.0, 35.0, 50.0, 70.0, 90.0000001)\n    b_band_labels = ("0-10", "10-20", "20-35", "35-50", "50-70", "70-90")\n    b_band = pd.cut(\n        abs_b_deg,\n        bins=b_band_edges,\n        labels=b_band_labels,\n        right=False,\n        include_lowest=True,\n    )\n\n    l_sector_edges = tuple(np.arange(0.0, 390.0, 30.0))\n    l_sector_labels = tuple(f"{int(start):03d}-{int(start + 30):03d}" for start in l_sector_edges[:-1])\n    l_sector = pd.cut(\n        l_deg,\n        bins=l_sector_edges,\n        labels=l_sector_labels,\n        right=False,\n        include_lowest=True,\n    )\n\n    b_band_str = b_band.astype(str)\n    l_sector_str = l_sector.astype(str)\n    crossed_regime = b_band_str + "|" + l_sector_str\n\n    return pd.DataFrame(\n        {\n            "eq_x": x_eq,\n            "eq_y": y_eq,\n            "eq_z": z_eq,\n            "gal_l_deg": l_deg,\n            "gal_b_deg": b_deg,\n            "gal_abs_b_deg": abs_b_deg,\n            "gal_sin_l": sin_l,\n            "gal_cos_l": cos_l,\n            "gal_sin_b": sin_b,\n            "gal_cos_b": cos_b,\n            "gal_plane_angular_distance_deg": abs_b_deg,\n            "gal_dist_to_galactic_center_deg": dist_to_galactic_center,\n            "gal_dist_to_galactic_anticenter_deg": dist_to_galactic_anticenter,\n            "gal_dist_to_north_pole_deg": dist_to_north_galactic_pole,\n            "gal_dist_to_south_pole_deg": dist_to_south_galactic_pole,\n            "gal_b_band": b_band_str,\n            "gal_l_sector": l_sector_str,\n            "gal_b_band_l_sector": crossed_regime,\n        },\n        index=raw.index,\n    )\n\nFEATURE_GROUPS = [\n    {\n        "name": "galactic_sightline_context",\n        "fn": add_galactic_sightline_context,\n        "depends_on": [],\n        "description": "Create Galactic coordinate-derived spatial features including smooth angular encodings, center/pole distances, and coarse latitude-longitude regime bins.",\n    }\n]'

HYPOTHESIS_000017_AUTOGLUON_001_PY_F265354A39_SOURCE = 'import numpy as np\nimport pandas as pd\n\n_COSMO_H0 = 70.0\n_COSMO_OMEGA_M = 0.3\n_COSMO_OMEGA_L = 0.7\n_COSMO_C_KM_S = 299792.458\n_COSMO_Z_MIN = 1e-4\n_COSMO_GRID_POINTS = 2048\n_COSMO_DL_MIN_MPC = 1.0e-4\n_COSMO_DL_MAX_MPC = 1.0e7\n_COSMO_ABS_MAG_MIN = -90.0\n_COSMO_ABS_MAG_MAX = 80.0\n_BANDS = ("u", "g", "r", "i", "z")\n_THRESHOLDS_M = (-10.0, -18.0, -23.0, -27.0)\n\n\ndef _luminosity_distance_mpc(redshift_for_distance):\n    redshift_for_distance = np.asarray(redshift_for_distance, dtype=np.float64)\n    if redshift_for_distance.size == 0:\n        return redshift_for_distance.copy()\n\n    z_max = float(np.max(redshift_for_distance))\n    if not np.isfinite(z_max):\n        z_max = float(_COSMO_Z_MIN)\n\n    # Build a fixed one-dimensional cosmology integral grid and re-use it for all rows.\n    z_grid = np.linspace(0.0, z_max, num=_COSMO_GRID_POINTS)\n    hz = np.sqrt(_COSMO_OMEGA_M * np.power(1.0 + z_grid, 3.0) + _COSMO_OMEGA_L)\n    inv_hz = 1.0 / hz\n\n    if _COSMO_GRID_POINTS > 1:\n        dz = z_grid[1] - z_grid[0]\n        seg = (inv_hz[:-1] + inv_hz[1:]) * 0.5 * dz\n        comoving = np.empty_like(z_grid)\n        comoving[0] = 0.0\n        np.cumsum(seg, out=comoving[1:])\n    else:\n        comoving = np.zeros_like(z_grid)\n\n    # Mpc = (c/H0) * (integral 0..z dz/E(z)); DL = (1+z) * D_C\n    dl = (1.0 + redshift_for_distance) * np.interp(redshift_for_distance, z_grid, comoving * (_COSMO_C_KM_S / _COSMO_H0))\n    dl = np.clip(dl, _COSMO_DL_MIN_MPC, _COSMO_DL_MAX_MPC)\n    return dl\n\n\ndef add_redshift_luminosity_plausibility(raw, deps, aux):\n    del deps, aux  # explicit dependency/aux declaration-only no-op\n    z = raw["redshift"].to_numpy(dtype=np.float64, copy=False)\n    z_eff = np.maximum(z, _COSMO_Z_MIN)\n\n    dist_mpc = _luminosity_distance_mpc(z_eff)\n    dist_mpc = np.clip(dist_mpc, _COSMO_DL_MIN_MPC, _COSMO_DL_MAX_MPC)\n    log10_dl = np.log10(dist_mpc)\n\n    abs_mag = {}\n    for band in _BANDS:\n        m_obs = raw[band].to_numpy(dtype=np.float64, copy=False)\n        m_abs = m_obs - 5.0 * log10_dl - 25.0\n        abs_mag[band] = np.clip(m_abs, _COSMO_ABS_MAG_MIN, _COSMO_ABS_MAG_MAX)\n\n    abs_matrix = np.column_stack((abs_mag["u"], abs_mag["g"], abs_mag["r"], abs_mag["i"], abs_mag["z"]))\n    abs_center_ri = 0.5 * (abs_mag["r"] + abs_mag["i"])\n    abs_brightest = np.min(abs_matrix, axis=1)\n    abs_faintest = np.max(abs_matrix, axis=1)\n    abs_spread = abs_faintest - abs_brightest\n    abs_mean = np.mean(abs_matrix, axis=1)\n\n    thresh_stellar, thresh_galaxy, thresh_qso, thresh_extreme = _THRESHOLDS_M\n\n    features = {\n        "redshift_non_positive": z <= 0.0,\n        "redshift_very_low": z < 0.01,\n        "redshift_for_distance": z_eff,\n        "luminosity_distance_mpc": dist_mpc,\n        "abs_mag_u": abs_mag["u"],\n        "abs_mag_g": abs_mag["g"],\n        "abs_mag_r": abs_mag["r"],\n        "abs_mag_i": abs_mag["i"],\n        "abs_mag_z": abs_mag["z"],\n        "abs_mag_ri_center": abs_center_ri,\n        "abs_mag_brightest_band": abs_brightest,\n        "abs_mag_faintest_band": abs_faintest,\n        "abs_mag_band_spread": abs_spread,\n        "abs_mag_band_mean": abs_mean,\n        "abs_mag_margin_to_stellar_scale": abs_center_ri - thresh_stellar,\n        "abs_mag_margin_to_galaxy_scale": abs_center_ri - thresh_galaxy,\n        "abs_mag_margin_to_quasar_scale": abs_center_ri - thresh_qso,\n        "abs_mag_margin_to_extreme_quasar_scale": abs_center_ri - thresh_extreme,\n        "abs_mag_r_margin_to_stellar_scale": abs_mag["r"] - thresh_stellar,\n        "abs_mag_r_margin_to_galaxy_scale": abs_mag["r"] - thresh_galaxy,\n        "abs_mag_r_margin_to_quasar_scale": abs_mag["r"] - thresh_qso,\n        "abs_mag_r_margin_to_extreme_quasar_scale": abs_mag["r"] - thresh_extreme,\n        "abs_band_spread_uirz": (abs_mag["u"] - abs_mag["r"]) + (abs_mag["r"] - abs_mag["i"]) + (abs_mag["i"] - abs_mag["z"]),\n    }\n\n    return pd.DataFrame(features, index=raw.index)\n\n\nFEATURE_GROUPS = [\n    {\n        "name": "redshift_luminosity_plausibility",\n        "fn": add_redshift_luminosity_plausibility,\n        "depends_on": [],\n        "description": "Convert apparent ugri z magnitudes into redshift-scaled pseudo absolute magnitudes with robust distance-distance proxies and regime-distance summaries.",\n    }\n]'

HYPOTHESIS_000022_AUTOGLUON_004_PY_10E21EEB73_SOURCE = 'import numpy as np\nimport pandas as pd\nfrom collections import deque\n\n_AIDE_RA_BINS = 720\n_AIDE_DEC_BINS = 338\n_AIDE_SHRINKAGE_K = 20.0\n_AIDE_FALLBACK_THRESHOLD = 20\n_AIDE_REDSHIFT_MIN = 0.0\n_AIDE_REDSHIFT_MAX = 7.0\n_AIDE_EPS = 1e-6\n\n_AIDE_FEATURE_ORDER = (\n    "u",\n    "g",\n    "r",\n    "i",\n    "z",\n    "redshift_clipped",\n    "u_minus_g",\n    "g_minus_r",\n    "r_minus_i",\n    "i_minus_z",\n    "u_minus_i",\n    "u_minus_r",\n    "g_minus_z",\n    "r_minus_z",\n    "u_minus_2r_plus_i",\n    "g_minus_2i_plus_z",\n)\n\n_AIDE_COLOR_SHAPE_FEATURES = (\n    "u_minus_g",\n    "g_minus_r",\n    "r_minus_i",\n    "i_minus_z",\n    "u_minus_i",\n    "u_minus_r",\n    "g_minus_z",\n    "r_minus_z",\n    "u_minus_2r_plus_i",\n    "g_minus_2i_plus_z",\n)\n\n\ndef _safe_divide(numerator, denominator):\n    out = np.full_like(numerator, np.nan, dtype=np.float64)\n    mask = denominator > 0\n    out[mask] = numerator[mask] / denominator[mask]\n    return out\n\n\ndef _build_cell_index(alpha, delta):\n    alpha_clean = np.where(np.isfinite(alpha), alpha, 0.0)\n    delta_clean = np.where(np.isfinite(delta), delta, -90.0)\n\n    ra_bin = np.floor(np.mod(alpha_clean, 360.0) * 2.0).astype(np.int32)\n    ra_bin = np.clip(ra_bin, 0, _AIDE_RA_BINS - 1)\n\n    dec_bin = np.floor((delta_clean + 90.0) * 2.0).astype(np.int32)\n    dec_bin = np.clip(dec_bin, 0, _AIDE_DEC_BINS - 1)\n\n    cell_idx = ra_bin * _AIDE_DEC_BINS + dec_bin\n    return ra_bin, dec_bin, cell_idx\n\n\ndef _nearest_nonempty_lookup(cell_counts, ra_bins, dec_bins):\n    n_cells = ra_bins * dec_bins\n    nearest = np.full(n_cells, -1, dtype=np.int32)\n    dist = np.full(n_cells, -1, dtype=np.int32)\n\n    sources = np.flatnonzero(cell_counts > 0)\n    if sources.size == 0:\n        return nearest, dist\n\n    q = deque()\n    for src in sources:\n        nearest[src] = src\n        dist[src] = 0\n        q.append(src)\n\n    while q:\n        cur = q.popleft()\n        cur_ra = cur // dec_bins\n        cur_dec = cur - cur_ra * dec_bins\n        nd = dist[cur] + 1\n\n        ra_minus = cur_ra - 1\n        if ra_minus < 0:\n            ra_minus = ra_bins - 1\n        nb = ra_minus * dec_bins + cur_dec\n        if dist[nb] < 0:\n            dist[nb] = nd\n            nearest[nb] = nearest[cur]\n            q.append(nb)\n\n        ra_plus = cur_ra + 1\n        if ra_plus >= ra_bins:\n            ra_plus = 0\n        nb = ra_plus * dec_bins + cur_dec\n        if dist[nb] < 0:\n            dist[nb] = nd\n            nearest[nb] = nearest[cur]\n            q.append(nb)\n\n        if cur_dec > 0:\n            nb = cur_ra * dec_bins + (cur_dec - 1)\n            if dist[nb] < 0:\n                dist[nb] = nd\n                nearest[nb] = nearest[cur]\n                q.append(nb)\n\n        if cur_dec + 1 < dec_bins:\n            nb = cur_ra * dec_bins + (cur_dec + 1)\n            if dist[nb] < 0:\n                dist[nb] = nd\n                nearest[nb] = nearest[cur]\n                q.append(nb)\n\n    return nearest, dist\n\n\ndef _compute_cell_stats(values, cell_idx, n_cells):\n    values = np.asarray(values, dtype=np.float64)\n    finite = np.isfinite(values)\n    cell_mean = np.full(n_cells, np.nan, dtype=np.float64)\n    cell_std = np.full(n_cells, np.nan, dtype=np.float64)\n\n    if not np.any(finite):\n        return cell_mean, cell_std, np.nan, np.nan, _AIDE_EPS\n\n    idx = cell_idx[finite]\n    vals = values[finite]\n\n    counts = np.bincount(idx, weights=np.ones(vals.shape[0], dtype=np.float64), minlength=n_cells).astype(np.int32)\n    sums = np.bincount(idx, weights=vals, minlength=n_cells)\n    sumsq = np.bincount(idx, weights=vals * vals, minlength=n_cells)\n\n    valid = counts > 0\n    cell_mean[valid] = sums[valid] / counts[valid]\n\n    var = np.zeros(n_cells, dtype=np.float64)\n    var[valid] = np.maximum(sumsq[valid] / counts[valid] - cell_mean[valid] * cell_mean[valid], 0.0)\n    cell_std[valid] = np.sqrt(var[valid])\n\n    global_mean = np.mean(vals)\n    global_std = np.sqrt(np.mean((vals - global_mean) ** 2))\n\n    if np.any(valid):\n        cell_std_vals = cell_std[valid]\n        sigma_floor = np.nanpercentile(cell_std_vals, 0.1)\n        if not np.isfinite(sigma_floor) or sigma_floor <= _AIDE_EPS:\n            pos = cell_std_vals[cell_std_vals > _AIDE_EPS]\n            if pos.size > 0:\n                sigma_floor = np.nanpercentile(pos, 0.1)\n            elif np.isfinite(global_std) and global_std > _AIDE_EPS:\n                sigma_floor = global_std\n            else:\n                sigma_floor = _AIDE_EPS\n    else:\n        sigma_floor = _AIDE_EPS\n\n    if not np.isfinite(sigma_floor) or sigma_floor <= 0:\n        sigma_floor = _AIDE_EPS\n\n    return cell_mean, cell_std, global_mean, global_std, sigma_floor\n\n\ndef add_aide_sky_cell_local_residuals(raw, deps, aux):\n    alpha = pd.to_numeric(raw["alpha"], errors="coerce").to_numpy(dtype=np.float64)\n    delta = pd.to_numeric(raw["delta"], errors="coerce").to_numpy(dtype=np.float64)\n    idx = raw.index\n    n = len(raw)\n\n    if n == 0:\n        return pd.DataFrame(index=idx)\n\n    ra_bin, dec_bin, cell_idx = _build_cell_index(alpha, delta)\n    n_cells = _AIDE_RA_BINS * _AIDE_DEC_BINS\n\n    cell_counts = np.bincount(cell_idx, minlength=n_cells).astype(np.int32)\n    n_cell = cell_counts[cell_idx].astype(np.float64)\n\n    ra_minus = (ra_bin - 1) % _AIDE_RA_BINS\n    ra_plus = (ra_bin + 1) % _AIDE_RA_BINS\n    dec_minus = dec_bin - 1\n    dec_plus = dec_bin + 1\n\n    counts_grid = cell_counts.reshape(_AIDE_RA_BINS, _AIDE_DEC_BINS)\n\n    n_neigh = (\n        counts_grid[ra_bin, dec_bin]\n        + counts_grid[ra_minus, dec_bin]\n        + counts_grid[ra_plus, dec_bin]\n    ).astype(np.float64)\n\n    mid_mask = dec_bin > 0\n    if np.any(mid_mask):\n        n_neigh[mid_mask] += (\n            counts_grid[ra_minus[mid_mask], dec_minus[mid_mask]]\n            + counts_grid[ra_bin[mid_mask], dec_minus[mid_mask]]\n            + counts_grid[ra_plus[mid_mask], dec_minus[mid_mask]]\n        )\n\n    plus_mask = dec_plus < _AIDE_DEC_BINS\n    if np.any(plus_mask):\n        n_neigh[plus_mask] += (\n            counts_grid[ra_minus[plus_mask], dec_plus[plus_mask]]\n            + counts_grid[ra_bin[plus_mask], dec_plus[plus_mask]]\n            + counts_grid[ra_plus[plus_mask], dec_plus[plus_mask]]\n        )\n\n    concentration = n_cell / (n_neigh + _AIDE_EPS)\n\n    nearest_idx, nearest_dist = _nearest_nonempty_lookup(cell_counts, _AIDE_RA_BINS, _AIDE_DEC_BINS)\n    fallback_idx = nearest_idx[cell_idx].astype(np.int32)\n    fallback_dist = nearest_dist[cell_idx].astype(np.float64)\n\n    neighbor_cells = np.stack(\n        (\n            ra_minus * _AIDE_DEC_BINS + dec_minus,\n            ra_bin * _AIDE_DEC_BINS + dec_minus,\n            ra_plus * _AIDE_DEC_BINS + dec_minus,\n            ra_minus * _AIDE_DEC_BINS + dec_bin,\n            ra_plus * _AIDE_DEC_BINS + dec_bin,\n            ra_minus * _AIDE_DEC_BINS + dec_plus,\n            ra_bin * _AIDE_DEC_BINS + dec_plus,\n            ra_plus * _AIDE_DEC_BINS + dec_plus,\n        ),\n        axis=1,\n    )\n    neighbor_cells = np.where(\n        (neighbor_cells == cell_idx[:, None]) | (neighbor_cells < 0),\n        -1,\n        neighbor_cells,\n    )\n    neighbor_counts = np.where(neighbor_cells >= 0, cell_counts[neighbor_cells], -1)\n    neighbor_has = neighbor_counts > 0\n    neighbor_any = np.any(neighbor_has, axis=1)\n    neighbor_first = np.argmax(neighbor_has.astype(np.int8), axis=1)\n    neighbor_best = neighbor_cells[np.arange(n), neighbor_first]\n    neighbor_best = np.where(neighbor_any, neighbor_best, cell_idx)\n\n    sparse_mask = n_cell < float(_AIDE_FALLBACK_THRESHOLD)\n    use_alt = sparse_mask & (fallback_dist == 0.0) & neighbor_any\n\n    fallback_idx = np.where(use_alt, neighbor_best, fallback_idx)\n    fallback_dist = np.where(use_alt, 1.0, fallback_dist)\n\n    fallback_n_cell = cell_counts[fallback_idx].astype(np.float64)\n    fallback_w = fallback_n_cell / (fallback_n_cell + _AIDE_SHRINKAGE_K)\n    use_fallback = sparse_mask\n\n    u = pd.to_numeric(raw["u"], errors="coerce").to_numpy(dtype=np.float64)\n    g = pd.to_numeric(raw["g"], errors="coerce").to_numpy(dtype=np.float64)\n    r = pd.to_numeric(raw["r"], errors="coerce").to_numpy(dtype=np.float64)\n    i = pd.to_numeric(raw["i"], errors="coerce").to_numpy(dtype=np.float64)\n    z = pd.to_numeric(raw["z"], errors="coerce").to_numpy(dtype=np.float64)\n    redshift = pd.to_numeric(raw["redshift"], errors="coerce").to_numpy(dtype=np.float64)\n    redshift_clipped = np.clip(redshift, _AIDE_REDSHIFT_MIN, _AIDE_REDSHIFT_MAX)\n\n    feature_vals = {\n        "u": u,\n        "g": g,\n        "r": r,\n        "i": i,\n        "z": z,\n        "redshift_clipped": redshift_clipped,\n        "u_minus_g": u - g,\n        "g_minus_r": g - r,\n        "r_minus_i": r - i,\n        "i_minus_z": i - z,\n        "u_minus_i": u - i,\n        "u_minus_r": u - r,\n        "g_minus_z": g - z,\n        "r_minus_z": r - z,\n        "u_minus_2r_plus_i": u - 2.0 * r + i,\n        "g_minus_2i_plus_z": g - 2.0 * i + z,\n    }\n\n    color_set = set(_AIDE_COLOR_SHAPE_FEATURES)\n\n    local_delta_sum = np.zeros(n, dtype=np.float64)\n    local_delta_abs_sum = np.zeros(n, dtype=np.float64)\n    local_delta_sq_sum = np.zeros(n, dtype=np.float64)\n    local_z_sum = np.zeros(n, dtype=np.float64)\n    local_z_abs_max = np.full(n, -np.inf, dtype=np.float64)\n    local_valid = np.zeros(n, dtype=np.int32)\n\n    local_color_delta_sum = np.zeros(n, dtype=np.float64)\n    local_color_delta_sq_sum = np.zeros(n, dtype=np.float64)\n    local_color_valid = np.zeros(n, dtype=np.int32)\n\n    fallback_delta_sum = np.zeros(n, dtype=np.float64)\n    fallback_delta_abs_sum = np.zeros(n, dtype=np.float64)\n    fallback_delta_sq_sum = np.zeros(n, dtype=np.float64)\n    fallback_z_sum = np.zeros(n, dtype=np.float64)\n    fallback_z_abs_max = np.full(n, -np.inf, dtype=np.float64)\n    fallback_valid = np.zeros(n, dtype=np.int32)\n\n    fallback_color_delta_sum = np.zeros(n, dtype=np.float64)\n    fallback_color_delta_sq_sum = np.zeros(n, dtype=np.float64)\n    fallback_color_valid = np.zeros(n, dtype=np.int32)\n\n    new_features = {}\n\n    for feat in _AIDE_FEATURE_ORDER:\n        vals = feature_vals[feat]\n        finite = np.isfinite(vals)\n\n        cell_mean, cell_std, global_mean, global_std, sigma_floor = _compute_cell_stats(vals, cell_idx, n_cells)\n\n        mu_local = (\n            n_cell * cell_mean[cell_idx] / (n_cell + _AIDE_SHRINKAGE_K)\n            + (1.0 - n_cell / (n_cell + _AIDE_SHRINKAGE_K)) * global_mean\n        )\n        sigma_local = (\n            n_cell * cell_std[cell_idx] / (n_cell + _AIDE_SHRINKAGE_K)\n            + (1.0 - n_cell / (n_cell + _AIDE_SHRINKAGE_K)) * global_std\n        )\n        sigma_local = np.where(np.isfinite(sigma_local), sigma_local, sigma_floor)\n        sigma_local = np.where(sigma_local < sigma_floor, sigma_floor, sigma_local)\n\n        local_delta = np.full(n, np.nan, dtype=np.float64)\n        local_z = np.full(n, np.nan, dtype=np.float64)\n\n        valid_local = finite & np.isfinite(mu_local) & np.isfinite(sigma_local)\n        if np.any(valid_local):\n            local_delta[valid_local] = vals[valid_local] - mu_local[valid_local]\n            local_z[valid_local] = local_delta[valid_local] / (sigma_local[valid_local] + _AIDE_EPS)\n\n            d = local_delta[valid_local]\n            zv = local_z[valid_local]\n\n            local_delta_sum[valid_local] += d\n            local_delta_abs_sum[valid_local] += np.abs(d)\n            local_delta_sq_sum[valid_local] += d * d\n            local_z_sum[valid_local] += zv\n            local_z_abs_max[valid_local] = np.maximum(local_z_abs_max[valid_local], np.abs(zv))\n            local_valid[valid_local] += 1\n\n            if feat in color_set:\n                local_color_delta_sum[valid_local] += d\n                local_color_delta_sq_sum[valid_local] += d * d\n                local_color_valid[valid_local] += 1\n\n        mu_fb = (\n            fallback_w * cell_mean[fallback_idx]\n            + (1.0 - fallback_w) * global_mean\n        )\n        sigma_fb = (\n            fallback_w * cell_std[fallback_idx]\n            + (1.0 - fallback_w) * global_std\n        )\n        sigma_fb = np.where(np.isfinite(sigma_fb), sigma_fb, sigma_floor)\n        sigma_fb = np.where(sigma_fb < sigma_floor, sigma_floor, sigma_fb)\n\n        fallback_delta = np.full(n, np.nan, dtype=np.float64)\n        fallback_z = np.full(n, np.nan, dtype=np.float64)\n\n        valid_fb = use_fallback & finite & np.isfinite(mu_fb) & np.isfinite(sigma_fb)\n        if np.any(valid_fb):\n            fallback_delta[valid_fb] = vals[valid_fb] - mu_fb[valid_fb]\n            fallback_z[valid_fb] = fallback_delta[valid_fb] / (sigma_fb[valid_fb] + _AIDE_EPS)\n\n            d_fb = fallback_delta[valid_fb]\n            z_fb = fallback_z[valid_fb]\n\n            fallback_delta_sum[valid_fb] += d_fb\n            fallback_delta_abs_sum[valid_fb] += np.abs(d_fb)\n            fallback_delta_sq_sum[valid_fb] += d_fb * d_fb\n            fallback_z_sum[valid_fb] += z_fb\n            fallback_z_abs_max[valid_fb] = np.maximum(fallback_z_abs_max[valid_fb], np.abs(z_fb))\n            fallback_valid[valid_fb] += 1\n\n            if feat in color_set:\n                fallback_color_delta_sum[valid_fb] += d_fb\n                fallback_color_delta_sq_sum[valid_fb] += d_fb * d_fb\n                fallback_color_valid[valid_fb] += 1\n\n        new_features[f"{feat}_cell_delta"] = local_delta\n        new_features[f"{feat}_cell_z"] = local_z\n\n    local_delta_mean = _safe_divide(local_delta_sum, local_valid.astype(np.float64))\n    local_delta_abs_mean = _safe_divide(local_delta_abs_sum, local_valid.astype(np.float64))\n    local_z_mean = _safe_divide(local_z_sum, local_valid.astype(np.float64))\n    local_delta_l2 = np.sqrt(local_delta_sq_sum)\n    local_z_abs_max = np.where(local_valid > 0, local_z_abs_max, np.nan)\n\n    local_color_mean = _safe_divide(local_color_delta_sum, local_color_valid.astype(np.float64))\n    local_color_var = _safe_divide(local_color_delta_sq_sum, local_color_valid.astype(np.float64)) - local_color_mean * local_color_mean\n    local_color_var = np.where(local_color_var < 0.0, 0.0, local_color_var)\n    local_shape_resid_std = np.full(n, np.nan, dtype=np.float64)\n    color_mask = local_color_valid > 0\n    local_shape_resid_std[color_mask] = np.sqrt(local_color_var[color_mask])\n\n    fallback_delta_mean = _safe_divide(fallback_delta_sum, fallback_valid.astype(np.float64))\n    fallback_delta_abs_mean = _safe_divide(fallback_delta_abs_sum, fallback_valid.astype(np.float64))\n    fallback_z_mean = _safe_divide(fallback_z_sum, fallback_valid.astype(np.float64))\n    fallback_delta_l2 = np.sqrt(fallback_delta_sq_sum)\n    fallback_z_abs_max = np.where(fallback_valid > 0, fallback_z_abs_max, np.nan)\n\n    fallback_color_mean = _safe_divide(fallback_color_delta_sum, fallback_color_valid.astype(np.float64))\n    fallback_color_var = _safe_divide(fallback_color_delta_sq_sum, fallback_color_valid.astype(np.float64)) - fallback_color_mean * fallback_color_mean\n    fallback_color_var = np.where(fallback_color_var < 0.0, 0.0, fallback_color_var)\n    fallback_shape_resid_std = np.full(n, np.nan, dtype=np.float64)\n    fb_color_mask = fallback_color_valid > 0\n    fallback_shape_resid_std[fb_color_mask] = np.sqrt(fallback_color_var[fb_color_mask])\n\n    cell_alpha_center = (ra_bin.astype(np.float64) + 0.5) * 0.5\n    cell_delta_center = (dec_bin.astype(np.float64) + 0.5) * 0.5 - 90.0\n\n    new_features.update(\n        {\n            "sky_cell_ra_bin": ra_bin.astype(np.float64),\n            "sky_cell_dec_bin": dec_bin.astype(np.float64),\n            "sky_cell_ra_center": cell_alpha_center,\n            "sky_cell_dec_center": cell_delta_center,\n            "sky_cell_n": n_cell,\n            "sky_cell_n_neigh": n_neigh,\n            "sky_cell_concentration": concentration,\n            "sky_cell_is_sparse": sparse_mask.astype(np.int8),\n            "sky_cell_fallback_used": use_fallback.astype(np.int8),\n            "sky_cell_fallback_dist": np.where(use_fallback, fallback_dist, np.nan),\n            "sky_cell_fallback_cell_n": np.where(use_fallback, fallback_n_cell, np.nan),\n            "sky_cell_local_delta_mean": local_delta_mean,\n            "sky_cell_local_delta_abs_mean": local_delta_abs_mean,\n            "sky_cell_local_delta_l1": local_delta_abs_sum,\n            "sky_cell_local_delta_l2": local_delta_l2,\n            "sky_cell_local_z_mean": local_z_mean,\n            "sky_cell_local_abs_z_max": local_z_abs_max,\n            "sky_cell_local_shape_resid_std": local_shape_resid_std,\n            "sky_cell_local_n_features": local_valid.astype(np.float64),\n            "sky_cell_fallback_delta_mean": fallback_delta_mean,\n            "sky_cell_fallback_delta_abs_mean": fallback_delta_abs_mean,\n            "sky_cell_fallback_delta_l1": fallback_delta_abs_sum,\n            "sky_cell_fallback_delta_l2": fallback_delta_l2,\n            "sky_cell_fallback_z_mean": fallback_z_mean,\n            "sky_cell_fallback_abs_z_max": fallback_z_abs_max,\n            "sky_cell_fallback_shape_resid_std": fallback_shape_resid_std,\n            "sky_cell_fallback_n_features": fallback_valid.astype(np.float64),\n        }\n    )\n\n    return pd.DataFrame(new_features, index=idx)\n\n\nFEATURE_GROUPS = [\n    {\n        "name": "aide_sky_cell_local_residuals",\n        "fn": add_aide_sky_cell_local_residuals,\n        "depends_on": [],\n        "description": "Spatial sky-cell residualization with shrinkage to local cell/global statistics and sparse-cell neighborhood fallback features.",\n    }\n]'

HYPOTHESIS_000026_AUTOGLUON_004_PY_55FDD09202_SOURCE = 'import numpy as np\nimport pandas as pd\n\n_GROUP_NAME = "aide_smooth_spline_sed_interactions"\n_ALPHA_KNOTS = 7\n_OTHER_KNOTS = 5\n_BSPLINE_DEGREE = 3\n_INTERACTION_BASIS = 2\n\n\ndef _coerce_series(values):\n    return pd.to_numeric(values, errors="coerce")\n\n\ndef _bounds_from_series(main_series, auxiliary_series=None):\n    combined = main_series if auxiliary_series is None else pd.concat([main_series, auxiliary_series], ignore_index=True)\n    arr = combined.to_numpy(dtype=float)\n    finite = np.isfinite(arr)\n    if not np.any(finite):\n        arr = main_series.to_numpy(dtype=float)\n        finite = np.isfinite(arr)\n    if not np.any(finite):\n        return 0.0, 1.0\n    lo = float(np.nanmin(arr[finite]))\n    hi = float(np.nanmax(arr[finite]))\n    if not np.isfinite(lo) or not np.isfinite(hi) or hi <= lo:\n        return 0.0, 1.0\n    return lo, hi\n\n\ndef _difference_series(raw_df, aux_df, left_col, right_col):\n    left = _coerce_series(raw_df[left_col])\n    right = _coerce_series(raw_df[right_col])\n    raw_series = left - right\n    aux_series = None\n    if isinstance(aux_df, pd.DataFrame) and not aux_df.empty and left_col in aux_df.columns and right_col in aux_df.columns:\n        left_aux = _coerce_series(aux_df[left_col])\n        right_aux = _coerce_series(aux_df[right_col])\n        aux_series = left_aux - right_aux\n    return raw_series, aux_series\n\n\ndef _manual_bspline_basis(values, lower, upper, n_internal_knots, degree=_BSPLINE_DEGREE):\n    x = np.asarray(values, dtype=float)\n    n = len(x)\n    if not np.isfinite(lower) or not np.isfinite(upper) or upper <= lower or n == 0:\n        out = np.full((n, 1), np.nan, dtype=np.float32)\n        finite = np.isfinite(x)\n        out[finite, 0] = 1.0\n        return out\n\n    n_internal = max(2, int(n_internal_knots))\n    internal = np.linspace(lower, upper, n_internal + 2)[1:-1]\n    knots = np.r_[np.repeat(lower, degree + 1), internal, np.repeat(upper, degree + 1)]\n    n_basis = len(knots) - degree - 1\n    out = np.full((n, n_basis), np.nan, dtype=np.float32)\n\n    finite = np.isfinite(x)\n    if not np.any(finite):\n        return out\n\n    xv = x.copy()\n    xv[~finite] = lower\n    xv = np.clip(xv, lower, upper)\n    xi = xv[finite]\n    m = len(knots)\n    N = np.zeros((len(xi), m - 1), dtype=np.float64)\n\n    left = xi[:, None] >= knots[:-1][None, :]\n    right = xi[:, None] < knots[1:][None, :]\n    N[:, : m - 1] = (left & right).astype(np.float64)\n    N[xi == upper, n_basis - 1] = 1.0\n\n    for d in range(1, degree + 1):\n        n_cols = m - d - 1\n        N_next = np.zeros((len(xi), n_cols), dtype=np.float64)\n        for i in range(n_cols):\n            d1 = knots[i + d] - knots[i]\n            d2 = knots[i + d + 1] - knots[i + 1]\n            left_term = 0.0\n            right_term = 0.0\n            if d1 != 0.0:\n                left_term = ((xi - knots[i]) / d1) * N[:, i]\n            if d2 != 0.0:\n                right_term = ((knots[i + d + 1] - xi) / d2) * N[:, i + 1]\n            N_next[:, i] = left_term + right_term\n        N = N_next\n\n    finite_idx = np.flatnonzero(finite)\n    out[finite_idx] = N.astype(np.float32)\n    return out\n\n\ndef _nonperiodic_cubic_basis(values, lower, upper, n_knots):\n    arr = _coerce_series(values).to_numpy(dtype=float)\n    n = len(arr)\n    n_knots = int(max(2, n_knots))\n    if n == 0:\n        return np.empty((0, 0), dtype=np.float32)\n    if not np.isfinite(lower) or not np.isfinite(upper) or upper <= lower:\n        out = np.full((n, 1), np.nan, dtype=np.float32)\n        finite = np.isfinite(arr)\n        out[finite, 0] = 1.0\n        return out\n\n    internal = np.linspace(lower, upper, n_knots + 2)[1:-1]\n    knots = np.r_[np.repeat(lower, _BSPLINE_DEGREE + 1), internal, np.repeat(upper, _BSPLINE_DEGREE + 1)]\n    n_basis = len(knots) - _BSPLINE_DEGREE - 1\n    out = np.full((n, n_basis), np.nan, dtype=np.float32)\n\n    finite = np.isfinite(arr)\n    if not np.any(finite):\n        return out\n\n    x = np.clip(arr[finite], lower, upper)\n    try:\n        from scipy.interpolate import BSpline\n\n        coeff = np.eye(n_basis)\n        spline = BSpline(knots, coeff, _BSPLINE_DEGREE, axis=0, extrapolate=False)\n        basis = spline(x).astype(np.float64)\n    except Exception:\n        basis = _manual_bspline_basis(arr[finite], lower, upper, n_knots, degree=_BSPLINE_DEGREE)\n\n    if basis.ndim == 1:\n        basis = basis[:, None]\n    finite_idx = np.flatnonzero(finite)\n    out[finite_idx] = basis.astype(np.float32)\n    return out\n\n\ndef _periodic_cubic_basis(values, lower, upper, n_knots):\n    arr = _coerce_series(values).to_numpy(dtype=float)\n    n = len(arr)\n    n_knots = int(max(3, n_knots))\n    if n == 0:\n        return np.empty((0, 0), dtype=np.float32)\n    if not np.isfinite(lower) or not np.isfinite(upper) or upper <= lower:\n        out = np.full((n, 1), np.nan, dtype=np.float32)\n        finite = np.isfinite(arr)\n        out[finite, 0] = 1.0\n        return out\n\n    out = np.full((n, n_knots), np.nan, dtype=np.float32)\n    finite = np.isfinite(arr)\n    if not np.any(finite):\n        return out\n\n    period = upper - lower\n    if not np.isfinite(period) or period <= 0.0:\n        fallback = _manual_bspline_basis(arr[finite], lower, upper, n_knots, degree=_BSPLINE_DEGREE)\n        fallback = np.asarray(fallback, dtype=np.float32)\n        if fallback.shape[1] >= n_knots:\n            fallback = fallback[:, :n_knots]\n        else:\n            pad = np.full((fallback.shape[0], n_knots - fallback.shape[1]), np.nan, dtype=np.float32)\n            fallback = np.concatenate([fallback, pad], axis=1)\n        out[np.flatnonzero(finite)] = fallback\n        return out\n\n    xw = ((arr[finite] - lower) % period) + lower\n    try:\n        from scipy.interpolate import CubicSpline\n\n        nodes = np.linspace(lower, upper, n_knots + 1)\n        y = np.zeros((len(nodes), n_knots), dtype=float)\n        for i in range(n_knots):\n            y[i, i] = 1.0\n            if i == 0:\n                y[-1, i] = 1.0\n        spline = CubicSpline(nodes, y, bc_type="periodic", axis=0)\n        basis = spline(xw).astype(np.float32)\n    except Exception:\n        basis = _manual_bspline_basis(xw, lower, upper, n_knots, degree=_BSPLINE_DEGREE)\n        basis = np.asarray(basis, dtype=np.float32)\n        if basis.shape[1] >= n_knots:\n            basis = basis[:, :n_knots]\n        else:\n            pad = np.full((basis.shape[0], n_knots - basis.shape[1]), np.nan, dtype=np.float32)\n            basis = np.concatenate([basis, pad], axis=1)\n\n    out[np.flatnonzero(finite)] = basis\n    return out\n\n\ndef _add_basis_columns(store, basis_matrix, prefix):\n    for i in range(basis_matrix.shape[1]):\n        store[f"{prefix}_spline_b{i + 1:02d}"] = basis_matrix[:, i]\n\n\ndef _add_interaction_columns(store, left_matrix, right_matrix, name, max_terms=_INTERACTION_BASIS):\n    if left_matrix.size == 0 or right_matrix.size == 0:\n        return\n    left_terms = left_matrix[:, : min(max_terms, left_matrix.shape[1])]\n    right_terms = right_matrix[:, : min(max_terms, right_matrix.shape[1])]\n    for i in range(left_terms.shape[1]):\n        for j in range(right_terms.shape[1]):\n            store[f"{name}_b{i + 1:02d}_x{j + 1:02d}"] = left_terms[:, i] * right_terms[:, j]\n\n\ndef add_aide_smooth_spline_sed_interactions(raw, deps, aux):\n    _ = deps\n    aux_df = aux if isinstance(aux, pd.DataFrame) else pd.DataFrame()\n\n    alpha = _coerce_series(raw["alpha"])\n    delta = _coerce_series(raw["delta"])\n    u = _coerce_series(raw["u"])\n    g = _coerce_series(raw["g"])\n    r = _coerce_series(raw["r"])\n    i_band = _coerce_series(raw["i"])\n    z_band = _coerce_series(raw["z"])\n    redshift = _coerce_series(raw["redshift"])\n\n    alpha_aux = _coerce_series(aux_df["alpha"]) if not aux_df.empty and "alpha" in aux_df.columns else None\n    delta_aux = _coerce_series(aux_df["delta"]) if not aux_df.empty and "delta" in aux_df.columns else None\n    u_aux = _coerce_series(aux_df["u"]) if not aux_df.empty and "u" in aux_df.columns else None\n    g_aux = _coerce_series(aux_df["g"]) if not aux_df.empty and "g" in aux_df.columns else None\n    r_aux = _coerce_series(aux_df["r"]) if not aux_df.empty and "r" in aux_df.columns else None\n    i_aux = _coerce_series(aux_df["i"]) if not aux_df.empty and "i" in aux_df.columns else None\n    z_aux = _coerce_series(aux_df["z"]) if not aux_df.empty and "z" in aux_df.columns else None\n    redshift_aux = _coerce_series(aux_df["redshift"]) if not aux_df.empty and "redshift" in aux_df.columns else None\n\n    u_g, u_g_aux = _difference_series(raw, aux_df, "u", "g")\n    g_r, g_r_aux = _difference_series(raw, aux_df, "g", "r")\n    r_i, r_i_aux = _difference_series(raw, aux_df, "r", "i")\n    i_z, i_z_aux = _difference_series(raw, aux_df, "i", "z")\n    u_r, u_r_aux = _difference_series(raw, aux_df, "u", "r")\n    g_i, g_i_aux = _difference_series(raw, aux_df, "g", "i")\n    r_z, r_z_aux = _difference_series(raw, aux_df, "r", "z")\n    u_z, u_z_aux = _difference_series(raw, aux_df, "u", "z")\n\n    redshift_hi = _bounds_from_series(redshift, redshift_aux)[1]\n    if not np.isfinite(redshift_hi):\n        redshift_hi = float(redshift.max(skipna=True))\n    if not np.isfinite(redshift_hi):\n        redshift_hi = 0.0\n    clipped_redshift = redshift.clip(lower=0.0, upper=redshift_hi)\n    clipped_redshift_aux = redshift_aux.clip(lower=0.0, upper=redshift_hi) if redshift_aux is not None else None\n\n    feature_blocks = {}\n\n    alpha_bounds = _bounds_from_series(alpha, alpha_aux)\n    feature_blocks["alpha"] = _periodic_cubic_basis(alpha, alpha_bounds[0], alpha_bounds[1], _ALPHA_KNOTS)\n\n    delta_bounds = _bounds_from_series(delta, delta_aux)\n    feature_blocks["delta"] = _nonperiodic_cubic_basis(delta, delta_bounds[0], delta_bounds[1], _OTHER_KNOTS)\n\n    u_bounds = _bounds_from_series(u, u_aux)\n    feature_blocks["u"] = _nonperiodic_cubic_basis(u, u_bounds[0], u_bounds[1], _OTHER_KNOTS)\n\n    g_bounds = _bounds_from_series(g, g_aux)\n    feature_blocks["g"] = _nonperiodic_cubic_basis(g, g_bounds[0], g_bounds[1], _OTHER_KNOTS)\n\n    r_bounds = _bounds_from_series(r, r_aux)\n    feature_blocks["r"] = _nonperiodic_cubic_basis(r, r_bounds[0], r_bounds[1], _OTHER_KNOTS)\n\n    i_bounds = _bounds_from_series(i_band, i_aux)\n    feature_blocks["i"] = _nonperiodic_cubic_basis(i_band, i_bounds[0], i_bounds[1], _OTHER_KNOTS)\n\n    z_bounds = _bounds_from_series(z_band, z_aux)\n    feature_blocks["z"] = _nonperiodic_cubic_basis(z_band, z_bounds[0], z_bounds[1], _OTHER_KNOTS)\n\n    clipped_z_bounds = _bounds_from_series(clipped_redshift, clipped_redshift_aux)\n    feature_blocks["clipped_redshift"] = _nonperiodic_cubic_basis(\n        clipped_redshift, clipped_z_bounds[0], clipped_z_bounds[1], _OTHER_KNOTS\n    )\n\n    u_g_bounds = _bounds_from_series(u_g, u_g_aux)\n    feature_blocks["u_g"] = _nonperiodic_cubic_basis(u_g, u_g_bounds[0], u_g_bounds[1], _OTHER_KNOTS)\n\n    g_r_bounds = _bounds_from_series(g_r, g_r_aux)\n    feature_blocks["g_r"] = _nonperiodic_cubic_basis(g_r, g_r_bounds[0], g_r_bounds[1], _OTHER_KNOTS)\n\n    r_i_bounds = _bounds_from_series(r_i, r_i_aux)\n    feature_blocks["r_i"] = _nonperiodic_cubic_basis(r_i, r_i_bounds[0], r_i_bounds[1], _OTHER_KNOTS)\n\n    i_z_bounds = _bounds_from_series(i_z, i_z_aux)\n    feature_blocks["i_z"] = _nonperiodic_cubic_basis(i_z, i_z_bounds[0], i_z_bounds[1], _OTHER_KNOTS)\n\n    u_r_bounds = _bounds_from_series(u_r, u_r_aux)\n    feature_blocks["u_r"] = _nonperiodic_cubic_basis(u_r, u_r_bounds[0], u_r_bounds[1], _OTHER_KNOTS)\n\n    g_i_bounds = _bounds_from_series(g_i, g_i_aux)\n    feature_blocks["g_i"] = _nonperiodic_cubic_basis(g_i, g_i_bounds[0], g_i_bounds[1], _OTHER_KNOTS)\n\n    r_z_bounds = _bounds_from_series(r_z, r_z_aux)\n    feature_blocks["r_z"] = _nonperiodic_cubic_basis(r_z, r_z_bounds[0], r_z_bounds[1], _OTHER_KNOTS)\n\n    u_z_bounds = _bounds_from_series(u_z, u_z_aux)\n    feature_blocks["u_z"] = _nonperiodic_cubic_basis(u_z, u_z_bounds[0], u_z_bounds[1], _OTHER_KNOTS)\n\n    out = {}\n    for name, matrix in feature_blocks.items():\n        _add_basis_columns(out, matrix, name)\n\n    _add_interaction_columns(out, feature_blocks["clipped_redshift"], feature_blocks["u_g"], "redshift_x_u_g")\n    _add_interaction_columns(out, feature_blocks["clipped_redshift"], feature_blocks["g_r"], "redshift_x_g_r")\n    _add_interaction_columns(out, feature_blocks["clipped_redshift"], feature_blocks["r_i"], "redshift_x_r_i")\n    _add_interaction_columns(out, feature_blocks["g_r"], feature_blocks["r_i"], "g_r_x_r_i")\n\n    return pd.DataFrame(out, index=raw.index)\n\n\nFEATURE_GROUPS = [\n    {\n        "name": _GROUP_NAME,\n        "fn": add_aide_smooth_spline_sed_interactions,\n        "depends_on": [],\n        "description": "Add cubic spline expansions for sky coordinates, photometry, clipped redshift, and color indices with compact interactions over redshift-color and adjacent color terms.",\n    }\n]'

